// MARK: - Secure Local Storage Service (Keychain-based)

class SecureStorageService {
    
    static let shared = SecureStorageService()
    
    private let serviceName = "com.passwordvault.storage"
    
    private init() {}
    
    // Save a password hash to the Keychain
    func savePasswordHash(_ hash: String, forAccount account: String) -> Bool {
        // First delete any existing entry
        deletePasswordHash(forAccount: account)
        
        guard let data = hash.data(using: .utf8) else { return false }
        
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: serviceName,
            kSecAttrAccount as String: account,
            kSecValueData as String: data,
            kSecAttrAccessible as String: kSecAttrAccessibleWhenUnlockedThisDeviceOnly
        ]
        
        let status = SecItemAdd(query as CFDictionary, nil)
        return status == errSecSuccess
    }
    
    // Retrieve a password hash from the Keychain
    func getPasswordHash(forAccount account: String) -> String? {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: serviceName,
            kSecAttrAccount as String: account,
            kSecReturnData as String: true,
            kSecMatchLimit as String: kSecMatchLimitOne
        ]
        
        var result: AnyObject?
        let status = SecItemCopyMatching(query as CFDictionary, &result)
        
        guard status == errSecSuccess, let data = result as? Data else { return nil }
        return String(data: data, encoding: .utf8)
    }
    
    // Delete a password hash from the Keychain
    @discardableResult
    func deletePasswordHash(forAccount account: String) -> Bool {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: serviceName,
            kSecAttrAccount as String: account
        ]
        
        let status = SecItemDelete(query as CFDictionary)
        return status == errSecSuccess || status == errSecItemNotFound
    }
    
    // Get all stored account names
    func getAllAccounts() -> [String] {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: serviceName,
            kSecReturnAttributes as String: true,
            kSecMatchLimit as String: kSecMatchLimitAll
        ]
        
        var result: AnyObject?
        let status = SecItemCopyMatching(query as CFDictionary, &result)
        
        guard status == errSecSuccess, let items = result as? [[String: Any]] else { return [] }
        
        return items.compactMap { $0[kSecAttrAccount as String] as? String }
    }
    
    // Check if an account exists
    func accountExists(_ account: String) -> Bool {
        return getPasswordHash(forAccount: account) != nil
    }
}

// MARK: - Authentication Manager

class AuthenticationManager {
    
    static let shared = AuthenticationManager()
    
    private let hashingService = PasswordHashingService.shared
    private let storageService = SecureStorageService.shared
    
    // Track failed attempts for brute-force protection
    private var failedAttempts: [String: (count: Int, lastAttempt: Date)] = [:]
    private let maxFailedAttempts = 5
    private let lockoutDuration: TimeInterval = 300 // 5 minutes
    
    private init() {}
    
    enum AuthError: Error, LocalizedError {
        case hashingFailed
        case storageFailed
        case accountNotFound
        case invalidPassword
        case accountLocked
        case accountAlreadyExists
        case weakPassword(String)
        
        var errorDescription: String? {
            switch self {
            case .hashingFailed: return "Failed to hash password"
            case .storageFailed: return "Failed to save credentials"
            case .accountNotFound: return "Account not found"
            case .invalidPassword: return "Invalid password"
            case .accountLocked: return "Account is temporarily locked due to too many failed attempts"
            case .accountAlreadyExists: return "Account already exists"
            case .weakPassword(let reason): return "Weak password: \(reason)"
            }
        }
    }
    
    // Register a new account with password
    func registerAccount(username: String, password: String) -> Result<Void, AuthError> {
        // Check if account already exists
        if storageService.accountExists(username) {
            return .failure(.accountAlreadyExists)
        }
        
        // Validate password strength
        if let weaknessReason = validatePasswordStrength(password) {
            return .failure(.weakPassword(weaknessReason))
        }
        
        // Hash the password
        guard let hash = hashingService.createPasswordHash(password) else {
            return .failure(.hashingFailed)
        }
        
        // Store the hash
        if storageService.savePasswordHash(hash, forAccount: username) {
            return .success(())
        } else {
            return .failure(.storageFailed)
        }
    }
    
    // Authenticate offline with stored credentials
    func authenticate(username: String, password: String) -> Result<Void, AuthError> {
        // Check for brute-force lockout
        if isAccountLocked(username) {
            return .failure(.accountLocked)
        }
        
        // Retrieve stored hash
        guard let storedHash = storageService.getPasswordHash(forAccount: username) else {
            return .failure(.accountNotFound)
        }
        
        // Verify password
        if hashingService.verifyPassword(password, againstHash: storedHash) {
            // Reset failed attempts on success
            failedAttempts.removeValue(forKey: username)
            return .success(())
        } else {
            recordFailedAttempt(username)
            return .failure(.invalidPassword)
        }
    }
    
    // Change password for an existing account
    func changePassword(username: String, currentPassword: String, newPassword: String) -> Result<Void, AuthError> {
        // First authenticate with current password
        let authResult = authenticate(username: username, password: currentPassword)
        
        switch authResult {
        case .failure(let error):
            return .failure(error)
        case .success:
            break
        }
        
        // Validate new password strength
        if let weaknessReason = validatePasswordStrength(newPassword) {
            return .failure(.weakPassword(weaknessReason))
        }
        
        // Hash new password
        guard let hash = hashingService.createPasswordHash(newPassword) else {
            return .failure(.hashingFailed)
        }
        
        // Store new hash
        if storageService.savePasswordHash(hash, forAccount: username) {
            return .success(())
        } else {
            return .failure(.storageFailed)
        }
    }
    
    // Delete an account
    func deleteAccount(username: String, password: String) -> Result<Void, AuthError> {
        let authResult = authenticate(username: username, password: password)
        
        switch authResult {
        case .failure(let error):
            return .failure(error)
        case .success:
            storageService.deletePasswordHash(forAccount: username)
            failedAttempts.removeValue(forKey: username)
            return .success(())
        }
    }
    
    // Get remaining lockout time in seconds
    func remainingLockoutTime(forAccount username: String) -> TimeInterval? {
        guard let attempts = failedAttempts[username],
              attempts.count >= maxFailedAttempts else { return nil }
        
        let elapsed = Date().timeIntervalSince(attempts.lastAttempt)
        let remaining = lockoutDuration - elapsed
        return remaining > 0 ? remaining : nil
    }
    
    // MARK: - Private Helpers
    
    private func validatePasswordStrength(_ password: String) -> String? {
        if password.count < 8 {
            return "Password must be at least 8 characters long"
        }
        
        let hasUppercase = password.rangeOfCharacter(from: .uppercaseLetters) != nil
        let hasLowercase = password.rangeOfCharacter(from: .lowercaseLetters) != nil
        let hasDigit = password.rangeOfCharacter(from: .decimalDigits) != nil
        let hasSpecial = password.rangeOfCharacter(from: CharacterSet.alphanumerics.inverted) != nil
        
        if !hasUppercase { return "Password must contain at least one uppercase letter" }
        if !hasLowercase { return "Password must contain at least one lowercase letter" }
        if !hasDigit { return "Password must contain at least one digit" }
        if !hasSpecial { return "Password must contain at least one special character" }
        
        return nil
    }
    
    private func isAccountLocked(_ username: String) -> Bool {
        guard let attempts = failedAttempts[username],
              attempts.count >= maxFailedAttempts else { return false }
        
        let elapsed = Date().timeIntervalSince(attempts.lastAttempt)
        if elapsed >= lockoutDuration {
            failedAttempts.removeValue(forKey: username)
            return false
        }
        return true
    }
    
    private func recordFailedAttempt(_ username: String) {
        if var existing = failedAttempts[username] {
            existing.count += 1
            existing.lastAttempt = Date()
            failedAttempts[username] = existing
        } else {
            failedAttempts[username] = (count: 1, lastAttempt: Date())
        }
    }
}

